from flask import Flask, request, jsonify, make_response
import jwt
from datetime import datetime, timedelta
import os
import sqlite3

app = Flask(__name__)
app.config['SECRET_KEY'] = 'your-secret-key'

# Database setup
db = sqlite3.connect('users.db')
cursor = db.cursor()
cursor.execute('''CREATE TABLE IF NOT EXISTS users (username TEXT, password TEXT)''')
db.commit()

def encode_token(username):
    payload = {
        'exp': datetime.utcnow() + timedelta(days=1),
        'iat': datetime.utcnow(),
        'sub': username
    }
    return jwt.encode(payload, app.config['SECRET_KEY'])

@app.route('/login', methods=['POST'])
def login():
    auth = request.authorization
    if not auth or not auth.username or not auth.password:
        return make_response('Could not verify your credentials with provided data.', 401, {'WWW-Authenticate': 'Basic realm="Login required"'})

    user = cursor.fetchone()
    if user and user[1] == auth.password:
        token = encode_token(auth.username)
        return jsonify({'token': token.decode('UTF-8')})
    else:
        return make_response('Bad username or password', 401, {'WWW-Authenticate': 'Basic realm="Login required"'})

@app.route('/protected')
def protected():
    if not 'token' in request.headers:
        return make_response('No token provided.', 401, {'WWW-Authenticate': 'Bearer realm="Protected area"'})

    try:
        data = jwt.decode(request.headers['token'], app.config['SECRET_KEY'])
        return jsonify({'user': data['sub']})
    except:
        return make_response('Invalid token.', 401, {'WWW-Authenticate': 'Bearer realm="Protected area"'})

if __name__ == "__main__":
    app.run(debug=True)